def solve(text):
    pairs = {')': '(', ']': '[', '}': '{'}
    stack = []
    for character in text:
        if character in '([{': stack.append(character)
        elif character in pairs:
            if not stack or stack.pop() != pairs[character]: return False
    return not stack

